import Foundation

func makeRequest(url: URL, method: HTTPMethod, headers: [String: String]? = nil, body: Data? = nil) async throws -> (Data, URLResponse) {
    var request = URLRequest(url: url)
    request.httpMethod = method.rawValue

    if let headers = headers {
        for (key, value) in headers {
            request.setValue(value, forHTTPHeaderField: key)
        }
    }

    let session = URLSession.shared
    let task = session.dataTask(with: request) { data, response, error in
        if let error = error {
            throw error
        }

        guard let httpResponse = response as? HTTPURLResponse else {
            fatalError("Invalid response type")
        }

        if httpResponse.statusCode >= 200 && httpResponse.statusCode < 300 {
            DispatchQueue.main.async {
                print("Request succeeded with status code \(httpResponse.statusCode)")
            }
        } else {
            let error = NSError(domain: "RequestError", code: httpResponse.statusCode, userInfo: [NSLocalizedDescriptionKey: "Request failed with status code \(httpResponse.statusCode)"])
            DispatchQueue.main.async {
                print("Request failed with error: \(error.localizedDescription)")
            }
            throw error
        }

        guard let data = data else {
            fatalError("Empty response data")
        }

        DispatchQueue.main.async {
            print("Received \(data.count) bytes of response data")
        }
    }

    task.resume()

    do {
        let (data, response) = try await task.result
        return (data, response)
    } catch {
        throw error
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case delete = "DELETE"
}

struct LegacyDevice {
    let ipAddress: String
    let port: Int
    let protocol: Protocol

    enum Protocol {
        case http, https
    }

    func url() -> URL? {
        var components = URLComponents()
        components.scheme = (protocol == .http ? "http" : "https")
        components.host = ipAddress
        components.port = port
        return components.url
    }
}

func exampleAPIRequest() async throws -> Data {
    let url = URL(string: "https://api.example.com/endpoint")!
    return try await makeRequest(url: url, method: .get)
}

func localDeviceRequest() async throws -> Data {
    let device = LegacyDevice(ipAddress: "192.168.0.1", port: 80, protocol: .http)
    guard let url = device.url() else { fatalError("Invalid URL") }
    return try await makeRequest(url: url, method: .get)
}